"function esc(v){return String(v==null?'':v).replace(/[&<>\\\"']/g,m=>{if(m==='&')return '&amp;';if(m==='<')return '&lt;';if(m==='>')return '&gt;';if(m==='\\\"')return '&quot;';return '&#39;';});}"
"function pick(v,d){return v===undefined||v===null?d:v;}"
"function t(k){return(I18N[lang]&&I18N[lang][k])||(I18N.en&&I18N.en[k])||k;}"
"function fmt(s,data){return String(s).replace(/\\\\{(\\\\w+)\\\\}/g,(_,k)=>data&&data[k]!==undefined?data[k]:'');}"
"function mapLabel(map,key){const v=map[key]||{};return v[lang]||v.en||v.ru||key;}"
"function normalizeBoardProfile(v){return BOARD_PROFILES.includes(v)?v:'esp32-c3-supermini';}"
"function boardProfileName(profile){return mapLabel(BOARD_PROFILE_LABELS,normalizeBoardProfile(profile));}"
"function allowedGpios(profile){const key=normalizeBoardProfile(profile);const gpios=ALLOWED_GPIOS_BY_PROFILE[key]||ALLOWED_GPIOS_BY_PROFILE['esp32-c3-supermini'];return gpios.slice();}"
"function gpioAllowed(profile,gpio){return allowedGpios(profile).includes(Number(gpio));}"
"function gpioAllowedHint(profile){const list=allowedGpios(profile).join(' ');return lang==='ru'?`разрешено: ${list}`:`allowed: ${list}`;}"
"function gpioForbiddenText(profile,gpio){return lang==='ru'?`GPIO${gpio} недопустим для профиля ${boardProfileName(profile)}`:`GPIO${gpio} is not allowed for profile ${boardProfileName(profile)}`;}"
"function invalidCurrentGpioLabel(profile,gpio){return lang==='ru'?`GPIO${gpio} (текущий, недопустим для ${boardProfileName(profile)})`:`GPIO${gpio} (current, not allowed for ${boardProfileName(profile)})`;}"
"function gpioSaveBlockedText(){return lang==='ru'?'Исправьте ошибки GPIO перед сохранением':'Fix GPIO errors before saving';}"
"function pinoutText(key){const ru={title:'Схема пинов',click:'Нажмите на GPIO, чтобы увидеть назначение.',schematic:'Super Mini построен по референсу Random Nerd Tutorials, LuatOS — по pinout из LuatOS/Manuals+.',free:'Свободен',output:'Выход',io:'Вход/кнопка',sensor:'Датчик',reserved:'Служебный',special:'Спецконтакт',blocked:'Недоступен',conflict:'Конфликт',power:'Питание',ground:'Земля',used_by:'Используется',profile:'Профиль',reason:'Причина'};const en={title:'Pinout map',click:'Click a GPIO pin to inspect its assignment.',schematic:'Super Mini follows the Random Nerd Tutorials reference, LuatOS follows the LuatOS/Manuals+ pinout.',free:'Free',output:'Output',io:'Input/button',sensor:'Sensor',reserved:'Reserved',special:'Special',blocked:'Blocked',conflict:'Conflict',power:'Power',ground:'Ground',used_by:'Used by',profile:'Profile',reason:'Reason'};const dict=lang==='ru'?ru:en;return dict[key]||key;}"
"function servicePinReason(gpio){const reason=SERVICE_PIN_REASONS[gpio];if(!reason)return'';return reason[lang]||reason.en||'';}"
"function summarizePinUsage(profile,gpio,usage){const entries=usage[String(gpio)]||[];const shareOk=entries.length>1&&entries.every(e=>e.share&&e.share===entries[0].share);if(entries.length>1&&!shareOk){return{state:'conflict',title:pinoutText('conflict'),lines:entries.map(e=>e.label)};}if(entries.length){const state=entries.some(e=>e.kind==='output')?'output':entries.some(e=>e.kind==='sensor')?'sensor':'io';return{state,title:pinoutText(state),lines:entries.map(e=>e.label)};}if(SERVICE_PIN_REASONS[gpio]&&!gpioAllowed(profile,gpio)){return{state:'reserved',title:pinoutText('reserved'),lines:[servicePinReason(gpio)]};}if(!gpioAllowed(profile,gpio)){return{state:'blocked',title:pinoutText('blocked'),lines:[gpioForbiddenText(profile,gpio)]};}return{state:'free',title:pinoutText('free'),lines:[]};}"
"function pinoutLegendHtml(){const items=[['power',pinoutText('power')],['ground',pinoutText('ground')],['free',pinoutText('free')],['output',pinoutText('output')],['io',pinoutText('io')],['sensor',pinoutText('sensor')],['special',pinoutText('special')],['reserved',pinoutText('reserved')],['blocked',pinoutText('blocked')],['conflict',pinoutText('conflict')]];return items.map(([state,label])=>`<span class='pin-chip'><i class='pin-${state}'></i>${esc(label)}</span>`).join('');}"
"function setMsg(msg,ok){const el=document.getElementById('msg');el.textContent=msg||'';el.className=ok?'ok':'err';}"
"function ensure(){cfg.outputs=Array.isArray(cfg.outputs)?cfg.outputs:[];cfg.inputs=Array.isArray(cfg.inputs)?cfg.inputs:[];cfg.buttons=Array.isArray(cfg.buttons)?cfg.buttons:[];cfg.sensors=Array.isArray(cfg.sensors)?cfg.sensors:[];cfg.device=cfg.device||{};cfg.connectivity=cfg.connectivity||{};cfg.connectivity.ap=cfg.connectivity.ap||{};cfg.connectivity.sta=cfg.connectivity.sta||{};cfg.connectivity.mqtt=cfg.connectivity.mqtt||{};}"
"function gpioOptions(selected,profile){const boardProfile=normalizeBoardProfile(profile);const options=allowedGpios(boardProfile);const numeric=Number(selected);if(selected!==undefined&&selected!==null&&selected!==''&&!Number.isNaN(numeric)&&!options.includes(numeric))options.push(numeric);options.sort((a,b)=>a-b);return options.map(g=>{const invalid=!gpioAllowed(boardProfile,g);const label=invalid?invalidCurrentGpioLabel(boardProfile,g):`GPIO${g}`;return `<option value='${g}' ${Number(selected)===g?'selected':''}>${esc(label)}</option>`;}).join('');}"
"function enumOptions(values,selected,map){return values.map(v=>`<option value='${esc(v)}' ${String(selected)===String(v)?'selected':''}>${esc(mapLabel(map||{},v))}</option>`).join('');}"
"function boardOptions(selected){return BOARD_PROFILES.map(v=>`<option value='${esc(v)}' ${String(selected)===String(v)?'selected':''}>${esc(mapLabel(BOARD_PROFILE_LABELS,v))}</option>`).join('');}"
"function refreshRaw(){document.getElementById('raw_cfg').value=JSON.stringify(cfg,null,2);}"
"function setField(section,idx,key,value){cfg[section][idx][key]=value;render();}"
"function setNested(section,idx,parent,key,value){cfg[section][idx][parent]=cfg[section][idx][parent]||{};cfg[section][idx][parent][key]=value;render();}"
"function removeItem(section,idx){cfg[section].splice(idx,1);render();}"
"function ioEntries(){const list=[];cfg.inputs.forEach((o,i)=>list.push({section:'inputs',idx:i,kind:'input',data:o}));cfg.buttons.forEach((o,i)=>list.push({section:'buttons',idx:i,kind:'button',data:o}));return list;}"
"function inputFromButton(src){return{id:src.id||'',name:src.name||'',type:'digital',enabled:src.enabled!==false,gpio:pick(src.gpio,0),pull:pick(src.pull,'up'),inverted:!!src.inverted,role:'generic_binary'};}"
"function buttonFromInput(src){return{id:src.id||'',name:src.name||'',enabled:src.enabled!==false,gpio:pick(src.gpio,0),pull:pick(src.pull,'up'),inverted:!!src.inverted,long_press_ms:1000,actions:{short:{type:'master_toggle'},long:{type:'none'}}};}"
"function changeIoKind(section,idx,nextKind){if(section==='inputs'&&nextKind==='input')return;if(section==='buttons'&&nextKind==='button')return;const src=cfg[section][idx];cfg[section].splice(idx,1);if(nextKind==='button'){cfg.buttons.push(buttonFromInput(src));}else{cfg.inputs.push(inputFromButton(src));}render();}"
"function actionEditor(section,idx,which,a){const cur=a||{};return `<div class='row3'><div><label>${t(which+'_action')}</label><select onchange=\\\"setNested('${section}',${idx},'actions','${which}',Object.assign((((cfg['${section}'][${idx}].actions||{})['${which}'])||{}),{type:this.value}))\\\">${enumOptions(BUTTON_ACTIONS,pick(cur.type,'none'),BUTTON_ACTION_LABELS)}</select></div><div><label>${t(which+'_target')}</label><input value='${esc(pick(cur.target,''))}' oninput=\\\"setNested('${section}',${idx},'actions','${which}',Object.assign((((cfg['${section}'][${idx}].actions||{})['${which}'])||{}),{target:this.value}))\\\"/></div><div><label>${t(which+'_value')}</label><input value='${esc(cur.step!==undefined?cur.step:(cur.value!==undefined?cur.value:''))}' oninput=\\\"const obj=Object.assign((((cfg['${section}'][${idx}].actions||{})['${which}'])||{}),{});if(obj.type==='set_output'){obj.value=(this.value==='true'||this.value==='1'||this.value==='on');}else{obj.step=Number(this.value||10);}setNested('${section}',${idx},'actions','${which}',obj)\\\"/></div></div>`;}"
"function renderOutputs(){const boardProfile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));document.getElementById('outputs').innerHTML=cfg.outputs.map((o,i)=>{const type=pick(o.type,'relay');return `<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||(`${t('output_name')} ${i+1}`))}</strong><button class='danger' onclick='removeItem(\\\"outputs\\\",${i})'>${t('remove')}</button></div><div class='row'><div><label>${t('id')}</label><input value='${esc(o.id||'')}' oninput='setField(\\\"outputs\\\",${i},\\\"id\\\",this.value)'/></div><div><label>${t('name')}</label><input value='${esc(o.name||'')}' oninput='setField(\\\"outputs\\\",${i},\\\"name\\\",this.value)'/></div></div><div class='row3'><div><label>${t('type')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"type\\\",this.value)'>${enumOptions(OUTPUT_TYPES,type,OUTPUT_TYPE_LABELS)}</select></div><div><label>${t('gpio')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"gpio\\\",Number(this.value))'>${gpioOptions(pick(o.gpio,0),boardProfile)}</select></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"enabled\\\",this.checked)' style='width:auto'/> ${t('enabled')}</label></div></div>${type==='relay'?`<div class='row'><div><label>${t('active_level')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"active_level\\\",Number(this.value))'><option value='1' ${Number(pick(o.active_level,1))===1?'selected':''}>1</option><option value='0' ${Number(pick(o.active_level,1))===0?'selected':''}>0</option></select></div><div><label><input type='checkbox' ${o.default_on?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"default_on\\\",this.checked)' style='width:auto'/> ${t('default_on')}</label></div></div>`:''}${type==='pwm'?`<div class='row3'><div><label>${t('freq_hz')}</label><input type='number' value='${esc(pick(o.freq_hz,1000))}' oninput='setField(\\\"outputs\\\",${i},\\\"freq_hz\\\",Number(this.value||0))'/></div><div><label>${t('default_level')}</label><input type='number' min='0' max='100' value='${esc(pick(o.default_level,0))}' oninput='setField(\\\"outputs\\\",${i},\\\"default_level\\\",Number(this.value||0))'/></div><div><label><input type='checkbox' ${o.inverted?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"inverted\\\",this.checked)' style='width:auto'/> ${t('inverted')}</label></div></div>`:''}${type==='ws2812'?`<div class='row3'><div><label>${t('pixels')}</label><input type='number' value='${esc(pick(o.pixel_count,1))}' oninput='setField(\\\"outputs\\\",${i},\\\"pixel_count\\\",Number(this.value||1))'/></div><div><label>${t('color_order')}</label><input value='${esc(pick(o.color_order,'GRB'))}' oninput='setField(\\\"outputs\\\",${i},\\\"color_order\\\",this.value)'/></div><div><label><input type='checkbox' ${o.default_power_on?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"default_power_on\\\",this.checked)' style='width:auto'/> ${t('default_on')}</label></div></div>`:''}</div>`;}).join('');}"
"function renderIo(){const boardProfile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));const items=ioEntries();document.getElementById('io').innerHTML=items.length?items.map((entry,row)=>{const o=entry.data;const sec=entry.section;const idx=entry.idx;const isButton=entry.kind==='button';return `<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||(`${isButton?t('button_name'):t('io_name')} ${row+1}`))}</strong><button class='danger' onclick='removeItem(\\\"${sec}\\\",${idx})'>${t('remove')}</button></div><div class='row3'><div><label>${t('kind')}</label><select onchange='changeIoKind(\\\"${sec}\\\",${idx},this.value)'><option value='input' ${!isButton?'selected':''}>${t('kind_input')}</option><option value='button' ${isButton?'selected':''}>${t('kind_button')}</option></select></div><div><label>${t('id')}</label><input value='${esc(o.id||'')}' oninput='setField(\\\"${sec}\\\",${idx},\\\"id\\\",this.value)'/></div><div><label>${t('name')}</label><input value='${esc(o.name||'')}' oninput='setField(\\\"${sec}\\\",${idx},\\\"name\\\",this.value)'/></div></div><div class='row3'><div><label>${t('gpio')}</label><select onchange='setField(\\\"${sec}\\\",${idx},\\\"gpio\\\",Number(this.value))'>${gpioOptions(pick(o.gpio,0),boardProfile)}</select></div><div><label>${t('pull')}</label><select onchange='setField(\\\"${sec}\\\",${idx},\\\"pull\\\",this.value)'>${enumOptions(PULLS,pick(o.pull,'up'),PULL_LABELS)}</select></div>${isButton?`<div><label>${t('long_press_ms')}</label><input type='number' value='${esc(pick(o.long_press_ms,1000))}' oninput='setField(\\\"${sec}\\\",${idx},\\\"long_press_ms\\\",Number(this.value||1000))'/></div>`:`<div><label>${t('role')}</label><select onchange='setField(\\\"${sec}\\\",${idx},\\\"role\\\",this.value)'>${enumOptions(INPUT_ROLES,pick(o.role,'generic_binary'),INPUT_ROLE_LABELS)}</select></div>`}</div><div class='row'><div><label><input type='checkbox' ${o.inverted?'checked':''} onchange='setField(\\\"${sec}\\\",${idx},\\\"inverted\\\",this.checked)' style='width:auto'/> ${t('inverted')}</label></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange='setField(\\\"${sec}\\\",${idx},\\\"enabled\\\",this.checked)' style='width:auto'/> ${t('enabled')}</label></div></div>${isButton?actionEditor(sec,idx,'short',(o.actions||{}).short)+actionEditor(sec,idx,'long',(o.actions||{}).long):''}</div>`;}).join(''):`<div class='muted'>${t('empty_io')}</div>`;}"
"function renderSensors(){const boardProfile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));document.getElementById('sensors').innerHTML=cfg.sensors.map((o,i)=>{const type=pick(o.type,'ds18b20_bus');return `<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||(`${t('sensor_name')} ${i+1}`))}</strong><button class='danger' onclick='removeItem(\\\"sensors\\\",${i})'>${t('remove')}</button></div><div class='row'><div><label>${t('id')}</label><input value='${esc(o.id||'')}' oninput='setField(\\\"sensors\\\",${i},\\\"id\\\",this.value)'/></div><div><label>${t('name')}</label><input value='${esc(o.name||'')}' oninput='setField(\\\"sensors\\\",${i},\\\"name\\\",this.value)'/></div></div><div class='row3'><div><label>${t('type')}</label><select onchange='setField(\\\"sensors\\\",${i},\\\"type\\\",this.value)'>${enumOptions(SENSOR_TYPES,type,SENSOR_TYPE_LABELS)}</select></div><div><label>${t('poll_sec')}</label><input type='number' value='${esc(pick(o.poll_interval_sec,30))}' oninput='setField(\\\"sensors\\\",${i},\\\"poll_interval_sec\\\",Number(this.value||30))'/></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange='setField(\\\"sensors\\\",${i},\\\"enabled\\\",this.checked)' style='width:auto'/> ${t('enabled')}</label></div></div>${type==='ds18b20_bus'?`<div><label>${t('gpio')}</label><select onchange='setField(\\\"sensors\\\",${i},\\\"gpio\\\",Number(this.value))'>${gpioOptions(pick(o.gpio,0),boardProfile)}</select></div>`:`<div class='row3'><div><label>${t('sda')}</label><select onchange='setField(\\\"sensors\\\",${i},\\\"sda_gpio\\\",Number(this.value))'>${gpioOptions(pick(o.sda_gpio,0),boardProfile)}</select></div><div><label>${t('scl')}</label><select onchange='setField(\\\"sensors\\\",${i},\\\"scl_gpio\\\",Number(this.value))'>${gpioOptions(pick(o.scl_gpio,1),boardProfile)}</select></div><div><label>${t('address')}</label><input value='${esc(pick(o.address,type==='aht20'?56:type==='sht3x'?68:118))}' oninput='setField(\\\"sensors\\\",${i},\\\"address\\\",Number(this.value||0))'/></div></div>`}</div>`;}).join('');}"
"function boardHint(){const key=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));const hint=BOARD_HINTS[key]||BOARD_HINTS['esp32-c3-supermini'];return hint[lang]||hint.en||'';}"
"function renderMeta(){const boardProfile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));document.getElementById('device_name').value=pick(cfg.device.name,'');document.getElementById('hostname').value=pick(cfg.connectivity.hostname,'esp32-c3');document.getElementById('ap_ssid').value=pick(cfg.connectivity.ap.ssid,'ESP32-SETUP');document.getElementById('ap_pass').value=pick(cfg.connectivity.ap.pass,'');document.getElementById('sta_ssid').value=pick(cfg.connectivity.sta.ssid,'');document.getElementById('sta_ssid').placeholder=t('select_network');document.getElementById('sta_pass').value=pick(cfg.connectivity.sta.pass,'');document.getElementById('mqtt_host').value=pick(cfg.connectivity.mqtt.host,'');document.getElementById('mqtt_port').value=pick(cfg.connectivity.mqtt.port,1883);document.getElementById('mqtt_user').value=pick(cfg.connectivity.mqtt.user,'');document.getElementById('mqtt_pass').value=pick(cfg.connectivity.mqtt.pass,'');document.getElementById('mqtt_topic_prefix').value=pick(cfg.connectivity.mqtt.topic_prefix,'');document.getElementById('mqtt_client_id').value=pick(cfg.connectivity.mqtt.client_id,'');document.getElementById('mqtt_discovery_prefix').value=pick(cfg.connectivity.mqtt.discovery_prefix,'homeassistant');document.getElementById('mqtt_enable').checked=cfg.connectivity.mqtt.enable===true;document.getElementById('mqtt_discovery').checked=cfg.connectivity.mqtt.discovery!==false;document.getElementById('mqtt_retain').checked=cfg.connectivity.mqtt.retain!==false;document.getElementById('board_profile').innerHTML=boardOptions(boardProfile);document.getElementById('board_profile').value=boardProfile;document.getElementById('board_hint').textContent=boardHint();}"
"function updateMetaFromInputs(){cfg.device.name=document.getElementById('device_name').value.trim();cfg.connectivity.hostname=document.getElementById('hostname').value.trim();cfg.connectivity.ap.ssid=document.getElementById('ap_ssid').value.trim();cfg.connectivity.ap.pass=document.getElementById('ap_pass').value;cfg.connectivity.sta.ssid=document.getElementById('sta_ssid').value.trim();cfg.connectivity.sta.pass=document.getElementById('sta_pass').value;cfg.connectivity.mqtt.enable=document.getElementById('mqtt_enable').checked;cfg.connectivity.mqtt.host=document.getElementById('mqtt_host').value.trim();cfg.connectivity.mqtt.port=Number(document.getElementById('mqtt_port').value||1883);cfg.connectivity.mqtt.user=document.getElementById('mqtt_user').value.trim();cfg.connectivity.mqtt.pass=document.getElementById('mqtt_pass').value;cfg.connectivity.mqtt.topic_prefix=document.getElementById('mqtt_topic_prefix').value.trim();cfg.connectivity.mqtt.client_id=document.getElementById('mqtt_client_id').value.trim();cfg.connectivity.mqtt.discovery_prefix=document.getElementById('mqtt_discovery_prefix').value.trim();cfg.connectivity.mqtt.discovery=document.getElementById('mqtt_discovery').checked;cfg.connectivity.mqtt.retain=document.getElementById('mqtt_retain').checked;cfg.device.board_profile=normalizeBoardProfile(document.getElementById('board_profile').value);}"
"function setBoardProfile(value){updateMetaFromInputs();cfg.device.board_profile=normalizeBoardProfile(value);render();}"
"function validateGpios(){const boardProfile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));const used={};const errors=[];const touch=(label,g)=>{if(g===undefined||g===null||g==='')return;const gpio=Number(g);if(!Number.isInteger(gpio)){errors.push(`${label}: invalid GPIO`);return;}if(!gpioAllowed(boardProfile,gpio))errors.push(`${label}: ${gpioForbiddenText(boardProfile,gpio)}`);const key=String(gpio);used[key]=used[key]||[];used[key].push(label);};cfg.outputs.forEach(o=>touch(`${t('output_name')} ${o.id||o.name||'?'}`,o.gpio));cfg.inputs.forEach(o=>touch(`${t('io_name')} ${o.id||o.name||'?'}`,o.gpio));cfg.buttons.forEach(o=>touch(`${t('button_name')} ${o.id||o.name||'?'}`,o.gpio));cfg.sensors.forEach(o=>{if(o.type==='ds18b20_bus'){touch(`${t('sensor_name')} ${o.id||o.name||'?'}`,o.gpio);}else{touch('i2c_sda',o.sda_gpio);touch('i2c_scl',o.scl_gpio);}});Object.entries(used).forEach(([gpio,list])=>{if(list.length>1&&!(list.every(v=>v==='i2c_sda')||list.every(v=>v==='i2c_scl')))errors.push(`GPIO${gpio}: ${list.join(', ')}`);});document.getElementById('gpio_summary').innerHTML=errors.length?`<span class='err'>${t('conflicts')}:</span><br>${errors.map(esc).join('<br>')}`:`<span class='ok'>${t('no_gpio_conflicts')}</span>`;return errors.length===0;}"
"function collectPinUsage(){const usage={};const add=(gpio,kind,label,share)=>{const num=Number(gpio);if(!Number.isInteger(num))return;const key=String(num);usage[key]=usage[key]||[];usage[key].push({kind,label,share:share||''});};cfg.outputs.forEach(o=>add(o.gpio,'output',`${t('output_name')} ${o.id||o.name||'?'}`,''));cfg.inputs.forEach(o=>add(o.gpio,'io',`${t('io_name')} ${o.id||o.name||'?'}`,''));cfg.buttons.forEach(o=>add(o.gpio,'io',`${t('button_name')} ${o.id||o.name||'?'}`,''));cfg.sensors.forEach(o=>{const name=`${t('sensor_name')} ${o.id||o.name||'?'}`;if(o.type==='ds18b20_bus'){add(o.gpio,'sensor',`${name} (${o.type||'sensor'})`,'');}else{add(o.sda_gpio,'sensor',`${name} SDA`,'i2c_sda');add(o.scl_gpio,'sensor',`${name} SCL`,'i2c_scl');}});return usage;}"
"function pinoutDetailsHtml(profile,gpio,usage){if(gpio===undefined||gpio===null||gpio==='')return `${esc(pinoutText('schematic'))}<br>${esc(pinoutText('click'))}`;const info=summarizePinUsage(profile,gpio,usage);const body=info.lines.length?info.lines.map(esc).join('<br>'):esc(pinoutText('free'));return `<strong>GPIO${gpio}</strong> · ${esc(info.title)}<br>${body}`;}"
"function pinSpecState(profile,pin,usage){if(pin.type==='power'||pin.type==='ground'||pin.type==='special')return{state:pin.type,title:pinoutText(pin.type),lines:[pin.label]};return summarizePinUsage(profile,pin.gpio,usage);}"
"function pinTagClass(tag){if(/^A\\d+$/.test(tag))return'pin-tag-adc';if(tag==='SCK'||tag==='MISO'||tag==='MOSI'||tag==='SS'||tag==='SPIHD'||tag==='SPIWP'||tag==='VDDSPI')return'pin-tag-spi';if(tag==='SDA'||tag==='SCL')return'pin-tag-i2c';if(tag==='RX'||tag==='TX'||/^U\\d/.test(tag))return'pin-tag-uart';if(tag==='BOOT'||tag==='PWM1'||tag==='PWM4'||tag==='USB-'||tag==='USB+')return'pin-tag-special';return'pin-tag-spi';}"
"function renderPinTags(pin,side,y){const tags=Array.isArray(pin.tags)?pin.tags:[];if(!tags.length)return'';const width=40;return tags.map((tag,idx)=>{const cls=pinTagClass(tag);const finalX=side==='left'?(10+idx*(width+6)):(442+idx*(width+6));return `<g class='pin-tag ${cls}'><rect class='pin-tag-box' x='${finalX}' y='${y}' width='${width}' height='20' rx='10' ry='10'/><text x='${finalX+(width/2)}' y='${y+13}' text-anchor='middle'>${esc(tag)}</text></g>`;}).join('');}"
"function buildPinoutSvg(profile,selected,usage){const spec=BOARD_PINOUTS[profile]||BOARD_PINOUTS['esp32-c3-supermini'];const rows=Math.max(spec.left.length,spec.right.length);const width=540;const height=Math.max(430,130+rows*42);const boardX=210;const boardY=34;const boardW=120;const boardH=height-68;const pinW=74;const pinH=24;const leftX=126;const rightX=340;const startY=74;const step=42;const renderSide=(pins,side)=>pins.map((pin,index)=>{const y=startY+index*step;const info=pinSpecState(profile,pin,usage);const gpio=pin.gpio;const selectedClass=(gpio!==undefined&&Number(selected)===gpio)?' pin-selected':'';const lineStart=side==='left'?boardX:boardX+boardW;const lineEnd=side==='left'?leftX+pinW:rightX;const boxX=side==='left'?leftX:rightX;const textX=boxX+(pinW/2);const hit=gpio!==undefined?`<rect class='pin-hit' x='${boxX-4}' y='${y-4}' width='${pinW+8}' height='${pinH+8}' onclick='showPinDetails(${gpio})'/>`:'';const tags=renderPinTags(pin,side,y+2);return `<g class='pin-${info.state}${selectedClass}'><line class='pin-wire' x1='${lineStart}' y1='${y+12}' x2='${lineEnd}' y2='${y+12}'/><rect class='pin-body' x='${boxX}' y='${y}' width='${pinW}' height='${pinH}' rx='12' ry='12'/><text class='pin-text' x='${textX}' y='${y+16}' text-anchor='middle'>${esc(pin.label)}</text>${tags}${hit}</g>`;}).join('');const notchX=boardX+boardW/2-18;return `<svg class='pinout-svg' viewBox='0 0 ${width} ${height}' role='img' aria-label='${esc(boardProfileName(profile))}'><rect class='board-shell' x='${boardX}' y='${boardY}' width='${boardW}' height='${boardH}' rx='20' ry='20'/><rect class='board-top' x='${boardX+24}' y='${boardY-8}' width='${boardW-48}' height='14' rx='6' ry='6'/><path class='board-notch' d='M ${notchX} ${boardY+56} h 36 l -8 18 h -20 z'/><text class='board-label' x='270' y='${boardY+boardH/2-6}' text-anchor='middle'>ESP32-C3</text><text class='board-label' x='270' y='${boardY+boardH/2+20}' text-anchor='middle'>${esc(spec.title)}</text><text class='board-sub' x='270' y='${boardY+boardH-18}' text-anchor='middle'>${esc(spec.subtitle)}</text>${renderSide(spec.left,'left')}${renderSide(spec.right,'right')}</svg>`;}"
"function renderPinout(selected){const profile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));const usage=collectPinUsage();document.getElementById('pinout_title').textContent=pinoutText('title');document.getElementById('pinout_profile').textContent=boardProfileName(profile);document.getElementById('pinout_legend').innerHTML=pinoutLegendHtml();document.getElementById('pinout_board').innerHTML=buildPinoutSvg(profile,selected,usage);document.getElementById('pinout_details').innerHTML=pinoutDetailsHtml(profile,selected,usage);}"
"function showPinDetails(gpio){renderPinout(Number(gpio));}"
"function applyI18n(){const subtitle=t('subtitle');const boardProfile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));document.documentElement.lang=(lang==='ru'?'ru':'en');document.title=t('title');document.getElementById('lang_select').value=lang;document.getElementById('page_title').textContent=t('title');document.getElementById('page_subtitle').textContent=subtitle;document.getElementById('page_subtitle').style.display=subtitle?'block':'none';document.getElementById('btn_save_apply').textContent=t('save_apply');document.getElementById('btn_factory_reset').textContent=t('factory_reset');document.getElementById('connectivity_title').textContent=t('connectivity');document.getElementById('lbl_device_name').textContent=t('device_name');document.getElementById('lbl_hostname').textContent=t('hostname');document.getElementById('lbl_ap_ssid').textContent=t('ap_ssid');document.getElementById('lbl_ap_pass').textContent=t('ap_pass');document.getElementById('lbl_sta_ssid').textContent=t('sta_ssid');document.getElementById('lbl_sta_pass').textContent=t('sta_pass');document.getElementById('lbl_mqtt_host').textContent=t('mqtt_host');document.getElementById('lbl_mqtt_port').textContent=t('mqtt_port');document.getElementById('lbl_mqtt_user').textContent=t('mqtt_user');document.getElementById('lbl_mqtt_pass').textContent=t('mqtt_pass');document.getElementById('lbl_topic_prefix').textContent=t('topic_prefix');document.getElementById('lbl_client_id').textContent=t('client_id');document.getElementById('lbl_discovery_prefix').textContent=t('discovery_prefix');document.getElementById('lbl_board_profile').textContent=t('board_profile');document.getElementById('lbl_mqtt_enable').textContent=t('mqtt_enabled');document.getElementById('lbl_mqtt_discovery').textContent=t('ha_discovery');document.getElementById('lbl_mqtt_retain').textContent=t('retain');document.getElementById('gpio_policy_title').textContent=t('gpio_policy');document.getElementById('allowed_hint').textContent=gpioAllowedHint(boardProfile);document.getElementById('reset_hint').textContent='reset: 9';document.getElementById('usb_hint').textContent='USB: 18 19';document.getElementById('uart_hint').textContent='UART: 20 21';document.getElementById('lbl_runtime_status').textContent=t('runtime_status');document.getElementById('outputs_title').textContent=t('outputs');document.getElementById('btn_add_output').textContent=t('add_output');document.getElementById('io_title').textContent=t('io_title');document.getElementById('btn_add_io').textContent=t('add_io');document.getElementById('sensors_title').textContent=t('sensors');document.getElementById('btn_add_sensor').textContent=t('add_sensor');document.getElementById('raw_title').textContent=t('raw_title');document.getElementById('raw_subtitle').textContent=t('raw_subtitle');}"
"async function ensureWifiScan(){if(wifiScanLoaded)return;if(wifiScanInFlight){await wifiScanInFlight;return;}wifiScanInFlight=scanWifi(true).finally(()=>{wifiScanInFlight=null;});await wifiScanInFlight;}"
"function render(){ensure();applyI18n();renderMeta();renderOutputs();renderIo();renderSensors();renderPinout();refreshRaw();validateGpios();}"
"function setLang(value){lang=(value==='en'?'en':'ru');localStorage.setItem('ui_lang',lang);render();loadStatus();}"
"function addOutput(){cfg.outputs.push({id:`out${cfg.outputs.length+1}`,name:`${t('output_name')} ${cfg.outputs.length+1}`,type:'relay',enabled:true,gpio:0,active_level:1,default_on:false});render();}"
"function addIo(){cfg.inputs.push({id:`in${cfg.inputs.length+1}`,name:`${t('io_name')} ${cfg.inputs.length+1}`,type:'digital',enabled:true,gpio:0,pull:'up',inverted:false,role:'generic_binary'});render();}"
"function addSensor(){cfg.sensors.push({id:`sensor${cfg.sensors.length+1}`,name:`${t('sensor_name')} ${cfg.sensors.length+1}`,type:'ds18b20_bus',enabled:true,gpio:0,poll_interval_sec:30});render();}"
"async function loadStatus(){const[rt,mods]=await Promise.all([fetch('/api/runtime').then(r=>r.json()),fetch('/api/modules').then(r=>r.json())]);document.getElementById('runtime').textContent=`${t('mode')}: ${rt.mode||'?'} | ${t('mqtt_state')}: ${rt.mqtt_connected?t('connected'):t('offline')} | ${t('ap_state')}: ${rt.ap_ssid||'-'}`;document.getElementById('runtime_status').textContent=JSON.stringify(mods,null,2);}"
"async function loadCfg(){cfg=await fetch('/api/config').then(r=>r.json());ensure();render();await loadStatus();await ensureWifiScan();}"
"async function scanWifi(initial){try{const r=await fetch('/api/wifi/scan');if(!r.ok)throw new Error(await r.text()||('HTTP '+r.status));const j=await r.json();const nets=j.networks||[];const list=document.getElementById('wifi_scan_list');list.innerHTML=nets.map(n=>`<option value='${esc(n.ssid)}'>${esc(n.ssid)} (${n.rssi} dBm)</option>`).join('');wifiScanLoaded=nets.length>0;setMsg(fmt(j.cached?t('found_networks_cached'):t('found_networks'),{count:nets.length}),true);}catch(e){wifiScanLoaded=false;if(!initial)setMsg(String(e),false);}}"
"async function saveOnly(){updateMetaFromInputs();render();if(!validateGpios())throw new Error(gpioSaveBlockedText());const r=await fetch('/api/config',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(cfg)});const text=await r.text();if(!r.ok)throw new Error(text||('HTTP '+r.status));setMsg(t('msg_saved'),true);}"
"async function saveAndApply(){try{await saveOnly();const r=await fetch('/api/apply',{method:'POST'});if(!r.ok)throw new Error(await r.text());setMsg(t('msg_saved_apply'),true);setTimeout(loadStatus,900);}catch(e){setMsg(String(e),false);}}"
"async function applyOnly(){try{const r=await fetch('/api/apply',{method:'POST'});if(!r.ok)throw new Error(await r.text());setMsg(t('msg_apply'),true);setTimeout(loadStatus,900);}catch(e){setMsg(String(e),false);}}"
"async function factoryReset(){try{if(!confirm(t('confirm_reset')))return;const r=await fetch('/api/factory-reset',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({confirm:'ERASE'})});if(!r.ok)throw new Error(await r.text());setMsg(t('msg_reset'),true);}catch(e){setMsg(String(e),false);}}"
"window.setField=setField;window.setNested=setNested;window.removeItem=removeItem;window.addOutput=addOutput;window.addIo=addIo;window.addSensor=addSensor;window.saveAndApply=saveAndApply;window.factoryReset=factoryReset;window.setLang=setLang;window.changeIoKind=changeIoKind;window.ensureWifiScan=ensureWifiScan;window.setBoardProfile=setBoardProfile;window.showPinDetails=showPinDetails;"
"loadCfg();"
"</script></div></body></html>";
